import React, { useState, useEffect } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import SearchBar from "./SearchBar";
import { FaUser, FaUpload, FaInfoCircle, FaHome, FaGraduationCap, FaSignInAlt, FaUserPlus, FaBars, FaTimes } from "react-icons/fa";
import "./Navbar.css";

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState(null);
  const navigate = useNavigate();
  const location = useLocation();

  // Handle scroll effect
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Close mobile menu when route changes
  useEffect(() => {
    setIsMenuOpen(false);
    setActiveDropdown(null);
  }, [location]);

  // Course dropdown items
  const courseItems = [
    { id: 1, name: "B.Tech", icon: "💻", path: "/course/1" },
    { id: 2, name: "BCA", icon: "📱", path: "/course/2" },
    { id: 3, name: "BBA", icon: "📊", path: "/course/3" },
    { id: 4, name: "MBA", icon: "💼", path: "/course/4" },
    { id: 5, name: "MCA", icon: "🎯", path: "/course/5" },
  ];

  // Main nav items
  const navItems = [
    { name: "Home", icon: <FaHome />, path: "/" },
    { name: "Courses", icon: <FaGraduationCap />, path: null, dropdown: true },
    { name: "Upload", icon: <FaUpload />, path: "/upload" },
    { name: "About", icon: <FaInfoCircle />, path: "/about" },
  ];

  // Handle dropdown toggle
  const toggleDropdown = (dropdown) => {
    setActiveDropdown(activeDropdown === dropdown ? null : dropdown);
  };

  return (
    <nav className={`navbar ${isScrolled ? "scrolled" : ""}`}>
      <div className="nav-container">
        
        {/* Logo */}
        <Link to="/" className="logo">
          <div className="logo-icon">📚</div>
          <div className="logo-text">
            <span className="logo-title">Study Portal</span>
            <span className="logo-subtitle">by KIET</span>
          </div>
        </Link>

        {/* Desktop Navigation */}
        <div className="desktop-nav">
          {navItems.map((item) => (
            item.dropdown ? (
              <div 
                key={item.name}
                className="nav-item dropdown-wrapper"
                onMouseEnter={() => setActiveDropdown('courses')}
                onMouseLeave={() => setActiveDropdown(null)}
              >
                <div 
                  className={`nav-link ${activeDropdown === 'courses' ? 'active' : ''}`}
                  onClick={() => toggleDropdown('courses')}
                >
                  <span className="nav-icon">{item.icon}</span>
                  {item.name}
                  <span className="dropdown-arrow">▼</span>
                </div>
                
                <div className={`dropdown-content ${activeDropdown === 'courses' ? 'show' : ''}`}>
                  {courseItems.map((course) => (
                    <Link 
                      key={course.id} 
                      to={course.path}
                      className="dropdown-item"
                    >
                      <span className="course-icon">{course.icon}</span>
                      <div>
                        <div className="course-name">{course.name}</div>
                        <div className="course-desc">
                          {course.id === 1 ? "Engineering" : 
                           course.id === 2 ? "Computer Applications" :
                           course.id === 3 ? "Business Administration" :
                           course.id === 4 ? "Master of Business" : "Computer Applications"}
                        </div>
                      </div>
                    </Link>
                  ))}
                </div>
              </div>
            ) : (
              <Link
                key={item.name}
                to={item.path}
                className={`nav-link ${location.pathname === item.path ? 'active' : ''}`}
              >
                <span className="nav-icon">{item.icon}</span>
                {item.name}
              </Link>
            )
          ))}

          {/* Search Bar */}
          <div className="search-wrapper">
            <SearchBar />
          </div>

          {/* Auth Buttons */}
          <div className="auth-section">
            <button 
              onClick={() => navigate("/login")} 
              className="auth-btn login-btn"
            >
              <FaSignInAlt className="btn-icon" />
              <span>Login</span>
            </button>
            <button 
              onClick={() => navigate("/register")} 
              className="auth-btn register-btn"
            >
              <FaUserPlus className="btn-icon" />
              <span>Register</span>
            </button>
          </div>
        </div>

        {/* Mobile Menu Button */}
        <button
          className="mobile-menu-btn"
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          aria-label="Toggle menu"
        >
          {isMenuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>

      {/* Mobile Navigation */}
      <div className={`mobile-nav ${isMenuOpen ? "open" : ""}`}>
        <div className="mobile-nav-header">
          <h3>Menu</h3>
          <button 
            className="close-menu-btn"
            onClick={() => setIsMenuOpen(false)}
          >
            <FaTimes />
          </button>
        </div>

        <div className="mobile-nav-links">
          {navItems.map((item) => (
            item.dropdown ? (
              <div key={item.name} className="mobile-dropdown">
                <div 
                  className="mobile-nav-link"
                  onClick={() => toggleDropdown('courses-mobile')}
                >
                  <span className="nav-icon">{item.icon}</span>
                  {item.name}
                  <span className="dropdown-arrow">
                    {activeDropdown === 'courses-mobile' ? '▲' : '▼'}
                  </span>
                </div>
                
                <div className={`mobile-dropdown-content ${activeDropdown === 'courses-mobile' ? 'show' : ''}`}>
                  {courseItems.map((course) => (
                    <Link 
                      key={course.id} 
                      to={course.path}
                      className="mobile-dropdown-item"
                      onClick={() => setIsMenuOpen(false)}
                    >
                      <span className="course-icon">{course.icon}</span>
                      <span>{course.name}</span>
                    </Link>
                  ))}
                </div>
              </div>
            ) : (
              <Link
                key={item.name}
                to={item.path}
                className={`mobile-nav-link ${location.pathname === item.path ? 'active' : ''}`}
                onClick={() => setIsMenuOpen(false)}
              >
                <span className="nav-icon">{item.icon}</span>
                {item.name}
              </Link>
            )
          ))}

          {/* Mobile Search */}
          <div className="mobile-search">
            <SearchBar />
          </div>

          {/* Mobile Auth Buttons */}
          <div className="mobile-auth">
            <button 
              onClick={() => {
                navigate("/login");
                setIsMenuOpen(false);
              }} 
              className="mobile-auth-btn login"
            >
              <FaSignInAlt />
              Login
            </button>
            <button 
              onClick={() => {
                navigate("/register");
                setIsMenuOpen(false);
              }} 
              className="mobile-auth-btn register"
            >
              <FaUserPlus />
              Register
            </button>
          </div>
        </div>
      </div>

      {/* Overlay for mobile menu */}
      {isMenuOpen && (
        <div className="mobile-overlay" onClick={() => setIsMenuOpen(false)}></div>
      )}
    </nav>
  );
};

export default Navbar;
